class HybridWebViewController(
    private val activity: ComponentActivity,
    private val webView: WebView,
    private val config: Config = Config()
) {
    data class Config(
        val allowedOrigins: Set<String> = emptySet(),
        val javascriptBridgeName: String = "NativeBridge",
        val enableDomStorage: Boolean = true,
        val enableFileAccess: Boolean = false,
        val enableContentAccess: Boolean = false,
        val appAssetsHost: String? = null
    )

    private val assetLoader: WebViewAssetLoader? =
        config.appAssetsHost?.let {
            WebViewAssetLoader.Builder()
                .addPathHandler("/assets/", WebViewAssetLoader.AssetsPathHandler(activity))
                .addPathHandler("/res/", WebViewAssetLoader.ResourcesPathHandler(activity))
                .build()
        }

    private val cameraPermissionLauncher: ActivityResultLauncher<String> =
        activity.registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            pendingCameraPermissionCallback?.invoke(granted)
            pendingCameraPermissionCallback = null
        }

    private var pendingCameraPermissionCallback: ((Boolean) -> Unit)? = null

    private val bridge = NativeBridge(activity, webView, config, ::requestCameraPermission)

    init {
        setupWebView()
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        val settings = webView.settings
        settings.javaScriptEnabled = true
        settings.domStorageEnabled = config.enableDomStorage
        settings.databaseEnabled = true
        settings.allowFileAccess = config.enableFileAccess
        settings.allowContentAccess = config.enableContentAccess
        settings.mediaPlaybackRequiresUserGesture = false
        settings.cacheMode = WebSettings.LOAD_DEFAULT
        settings.loadsImagesAutomatically = true
        settings.javaScriptCanOpenWindowsAutomatically = false
        settings.setSupportMultipleWindows(false)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            settings.safeBrowsingEnabled = true
        }

        webView.addJavascriptInterface(bridge, config.javascriptBridgeName)
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url ?: return false
                return !isAllowedUrl(url)
            }

            override fun shouldInterceptRequest(view: WebView?, request: WebResourceRequest?) =
                assetLoader?.shouldInterceptRequest(request?.url)
                    ?: super.shouldInterceptRequest(view, request)
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest?) {
                if (request == null) return
                val resources = request.resources?.toSet().orEmpty()
                if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                    requestCameraPermission { granted ->
                        if (granted) {
                            request.grant(request.resources)
                        } else {
                            request.deny()
                        }
                    }
                } else {
                    request.deny()
                }
            }
        }
    }

    fun loadUrl(url: String) {
        webView.loadUrl(url)
    }

    fun loadAppAsset(path: String = "/assets/index.html") {
        val host = config.appAssetsHost ?: "appassets.androidplatform.net"
        webView.loadUrl("https://$host$path")
    }

    fun onResume() {
        webView.onResume()
    }

    fun onPause() {
        webView.onPause()
    }

    fun destroy() {
        webView.removeJavascriptInterface(config.javascriptBridgeName)
        webView.stopLoading()
        webView.webChromeClient = null
        webView.webViewClient = null
        webView.destroy()
    }

    private fun requestCameraPermission(callback: (Boolean) -> Unit) {
        if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            callback(true)
            return
