    private fun isAllowedUrl(uri: Uri): Boolean {
        if (config.allowedOrigins.isEmpty()) return true
        val origin = "${uri.scheme}://${uri.host}${if (uri.port != -1) ":${uri.port}" else ""}"
        return config.allowedOrigins.contains(origin)
