class NativeBridge(
    private val context: Context,
    private val webView: WebView,
    private val config: HybridWebViewController.Config,
    private val requestCameraPermission: ((Boolean) -> Unit) -> Unit
) {
    private val storage = HybridLocalStorage(context)
    private val pushManager = HybridPushManager(context)

    @JavascriptInterface
    fun ping(): String = "pong"

    @JavascriptInterface
    fun getPlatform(): String = "android"

    @JavascriptInterface
    fun requestCameraAccess(callbackId: String) {
        requestCameraPermission { granted ->
            emitCallback(callbackId, JSONObject().put("granted", granted))
        }
    }

    @JavascriptInterface
    fun setItem(key: String, value: String): Boolean {
        storage.setItem(key, value)
        return true
    }

    @JavascriptInterface
    fun getItem(key: String): String? = storage.getItem(key)

    @JavascriptInterface
    fun removeItem(key: String): Boolean {
        storage.removeItem(key)
        return true
    }

    @JavascriptInterface
    fun clearStorage(): Boolean {
        storage.clear()
        return true
    }

    @JavascriptInterface
    fun getAllKeys(): String = JSONArray(storage.keys()).toString()

    @JavascriptInterface
    fun subscribePush(topic: String, callbackId: String) {
        val result = pushManager.subscribe(topic)
        emitCallback(
            callbackId,
            JSONObject()
                .put("success", result.success)
                .put("topic", topic)
                .put("token", result.token)
                .put("message", result.message)
        )
    }

    @JavascriptInterface
    fun unsubscribePush(topic: String, callbackId: String) {
        val result = pushManager.unsubscribe(topic)
        emitCallback(
            callbackId,
            JSONObject()
                .put("success", result.success)
                .put("topic", topic)
                .put("message", result.message)
        )
    }

    @JavascriptInterface
    fun getPushToken(): String = pushManager.getToken().orEmpty()

    @JavascriptInterface
    fun saveBase64File(fileName: String, base64Content: String): String {
        val bytes = android.util.Base64.decode(base64Content, android.util.Base64.DEFAULT)
        val dir = context.getExternalFilesDir(Environment.DIRECTORY_DOCUMENTS) ?: context.filesDir
        val file = File(dir, fileName)
        FileOutputStream(file).use { it.write(bytes) }
        return file.absolutePath
    }

    private fun emitCallback(callbackId: String, payload: JSONObject) {
        val script = """
            (function() {
              if (window.HybridNativeCallbacks && typeof window.HybridNativeCallbacks['$callbackId'] === 'function') {
                window.HybridNativeCallbacks['$callbackId'](${JSONObject.quote(payload.toString()) && ""});
              } else if (window.onNativeCallback) {
                window.onNativeCallback('$callbackId', ${payload.toString()});
              }
            })();
        """.trimIndent()

        val safeScript = """
            (function() {
              var payload = ${payload.toString()};
              if (window.HybridNativeCallbacks && typeof window.HybridNativeCallbacks['$callbackId'] === 'function') {
                window.HybridNativeCallbacks['$callbackId'](payload);
              } else if (window.onNativeCallback) {
                window.onNativeCallback('$callbackId', payload);
              }
            })();
        """.trimIndent()

        webView.post {
            webView.evaluateJavascript(safeScript, null)
        }
    }
}

class HybridLocalStorage(context: Context) {
    private val prefs = context.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)

    fun setItem(key: String, value: String) {
        prefs.edit().putString(key, value).apply()
    }

    fun getItem(key: String): String? = prefs.getString(key, null)

    fun removeItem(key: String) {
        prefs.edit().remove(key).apply()
    }

    fun clear() {
        prefs.edit().clear().apply()
    }

    fun keys(): Set<String> = prefs.all.keys
}

class HybridPushManager(private val context: Context) {
    data class Result(
        val success: Boolean,
        val token: String? = null,
        val message: String? = null
    )

    fun subscribe(topic: String): Result {
        val token = getToken()
        return Result(
            success = true,
            token = token,
            message = "Subscribed to $topic"
        )
    }

    fun unsubscribe(topic: String): Result {
        return Result(
            success = true,
            message = "Unsubscribed from $topic"
        )
    }

    fun getToken(): String? {
        val prefs = context.getSharedPreferences("hybrid_push", Context.MODE_PRIVATE)
        var token = prefs.getString("push_token", null)
        if (token == null) {
            token = "mock-token-${System.currentTimeMillis()}"
            prefs.edit().putString("push_token", token).apply()
        }
        return token
    }
}

class HybridWebAppActivity : ComponentActivity() {
    private lateinit var webView: WebView
