        if (!::webView.isInitialized) {
            webView = WebView(this)
            setContentView(webView)
            controller = HybridWebViewController(
                activity = this,
                webView = webView,
                config = HybridWebViewController.Config(
                    allowedOrigins = setOf(
                        "https://example.com",
                        "https://app.example.com"
                    ),
                    javascriptBridgeName = "NativeBridge",
                    enableDomStorage = true,
                    enableFileAccess = false,
                    enableContentAccess = false
                )
            )
            controller.loadUrl("https://app.example.com")
